from itertools import combinations


def _semipal_cost_alt(sub):
    length = len(sub)
    best = float('inf')
    for d in range(1, length):
        if length % d != 0:
            continue
        changes = 0
        for r in range(d):
            idxs = list(range(r, length, d))
            gl = len(idxs)
            for i in range(gl // 2):
                a = idxs[i]
                b = idxs[gl - 1 - i]
                if sub[a] != sub[b]:
                    changes += 1
        if changes < best:
            best = changes
    return best


class Solution:
    def minimumChanges(self, s, k):
        n = len(s)
        best = None
        for cuts in combinations(range(1, n), k - 1):
            bounds = [0] + list(cuts) + [n]
            total = 0
            for i in range(len(bounds) - 1):
                total += _semipal_cost_alt(s[bounds[i]:bounds[i + 1]])
            if best is None or total < best:
                best = total
        return best

