class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        def semipal_cost(sub):
            length = len(sub)
            best = float('inf')
            for d in range(1, length):
                if length % d != 0:
                    continue
                total = 0
                for r in range(d):
                    group = sub[r::d]
                    gl = len(group)
                    for i in range(gl // 2):
                        if group[i] != group[gl - 1 - i]:
                            total += 1
                if total < best:
                    best = total
            return best

        cost = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n):
            for j in range(i + 1, n + 1):
                cost[i][j] = semipal_cost(s[i:j])

        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for end in range(1, n + 1):
            for pieces in range(1, k + 1):
                best = INF
                for start in range(pieces - 1, end):
                    if dp[start][pieces - 1] == INF:
                        continue
                    cand = dp[start][pieces - 1] + cost[start][end]
                    if cand < best:
                        best = cand
                dp[end][pieces] = best
        return dp[n][k]

