var minimumChanges = function(s, k) {
    const n = s.length;
    const semipalCost = (sub) => {
        const length = sub.length;
        let best = Infinity;
        for (let d = 1; d < length; d++) {
            if (length % d !== 0) continue;
            let total = 0;
            for (let r = 0; r < d; r++) {
                const idxs = [];
                for (let p = r; p < length; p += d) idxs.push(p);
                const gl = idxs.length;
                for (let i = 0; i < Math.floor(gl / 2); i++) {
                    if (sub[idxs[i]] !== sub[idxs[gl - 1 - i]]) total++;
                }
            }
            if (total < best) best = total;
        }
        return best;
    };
    const cost = Array.from({ length: n + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j <= n; j++) {
            cost[i][j] = semipalCost(s.slice(i, j));
        }
    }
    const INF = Infinity;
    const dp = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(INF));
    dp[0][0] = 0;
    for (let end = 1; end <= n; end++) {
        for (let pieces = 1; pieces <= k; pieces++) {
            let best = INF;
            for (let start = pieces - 1; start < end; start++) {
                if (dp[start][pieces - 1] === INF) continue;
                const cand = dp[start][pieces - 1] + cost[start][end];
                if (cand < best) best = cand;
            }
            dp[end][pieces] = best;
        }
    }
    return dp[n][k];
};
